class Solution:
    def findSubstring(self, s: str, words: List[str]) -> List[int]:
        if not s or not words:
            return []
        word_len, num_words, total_len = len(words[0]), len(words), len(s)
        word_count = collections.Counter(words)
        result = []
        for i in range(word_len):
            left, right, seen, formed = i, i, {}, 0
            while right + word_len <= total_len:
                word = s[right:right + word_len]
                right += word_len
                if word not in word_count:
                    left = right
                    seen = {}
                    formed = 0
                else:
                    seen[word] = seen.get(word, 0) + 1
                    if seen[word] == word_count[word]:
                        formed += 1
                    while formed == num_words:
                        if right - left == num_words * word_len:
                            result.append(left)
                        word = s[left:left + word_len]
                        left += word_len
                        seen[word] -= 1
                        if seen[word] < word_count[word]:
                            formed -= 1
        return result
